// 1. Capture the input
let rawResponse = item.json.output || item.json.chatgptResponse || item.json.rawResponse || '';

function parseData(text) {
  let data = {
    classification: '',
    confidence: '',
    actual_reply: '',
    reasoning: '',
    key_phrases: '',
    red_flags: ''
  };

  // Try JSON parsing first (in case ChatGPT behaves perfectly)
  if (text.trim().startsWith('{')) {
    try {
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const json = JSON.parse(jsonMatch[0]);
        data.classification = json.classification || '';
        data.confidence = json.confidence || '';
        data.actual_reply = json.actual_reply || '';
        data.reasoning = json.reasoning || '';
        data.key_phrases = Array.isArray(json.key_phrases) ? json.key_phrases.join(', ') : (json.key_phrases || '');
        data.red_flags = Array.isArray(json.red_flags) ? json.red_flags.join(', ') : (json.red_flags || '');
        return data;
      }
    } catch (e) {
      // Fall through to text parsing
    }
  }

  // Clean up all Markdown formatting (backticks and asterisks)
  let cleanText = text.replace(/```[a-z]*\n?/gi, '').replace(/```/g, '').replace(/\*\*/g, '').trim();

  // Define our keys to look for
  const keysPattern = 'classification|confidence|actual_reply|reasoning|key_phrases|red_flags';

  // Lookahead ensures we capture everything up to the next key or the end of the text
  const lookahead = `(?=(?:${keysPattern.replace(/_/g, '[\\s_]*')})\\s*:|$)`;

  // Helper function to extract text blocks safely
  const extract = (key) => {
    // Allows "actual_reply:" or "actual reply:"
    const regexPattern = `${key.replace('_', '[\\s_]*')}\\s*:([\\s\\S]*?)${lookahead}`;
    const regex = new RegExp(regexPattern, 'i');
    const match = cleanText.match(regex);
    return match && match[1] ? match[1].trim() : '';
  };

  // Extract the blocks
  data.classification = extract('classification');
  data.confidence = extract('confidence');
  data.actual_reply = extract('actual_reply');
  data.reasoning = extract('reasoning');
  data.key_phrases = extract('key_phrases');
  data.red_flags = extract('red_flags');

  return data;
}

// 3. Execute the parsing logic
const parsed = parseData(rawResponse);

// 4. Clean up any leftover string quotes
const cleanClassification = parsed.classification.replace(/["']/g, '').trim();
const cleanConfidence = parsed.confidence.replace(/["']/g, '').trim();
const cleanActualReply = parsed.actual_reply.replace(/^["']|["']$/g, '').trim();
const cleanReasoning = parsed.reasoning.replace(/^["']|["']$/g, '').trim();
const cleanKeyPhrases = parsed.key_phrases.replace(/[\[\]"']/g, '').trim();
const cleanRedFlags = parsed.red_flags.replace(/[\[\]"']/g, '').replace(/none/i, '').trim();

// 5. Logic-friendly lowercasing for boolean flags
const lowClass = cleanClassification.toLowerCase();

// 6. Return the finalized object to n8n
return {
  classification: cleanClassification,
  confidence: cleanConfidence,
  actual_reply: cleanActualReply,
  reasoning: cleanReasoning,
  key_phrases: cleanKeyPhrases,
  red_flags: cleanRedFlags,
  is_positive: lowClass.includes('positive'),
  is_info_request: lowClass.includes('information request'),
  is_confirmed: lowClass.includes('confirmed interest'),
  is_negative: lowClass.includes('negative') || lowClass.includes('false positive'),
  parse_success: true
};

